import pytz
from datetime import datetime
import logging

logger = logging.getLogger(__name__)

Remote = self.remote_id

logger.info("[SCADA SQL] Starting Upsert Readings action")

def parse_value(v):
    if v is None:
        return None
    if isinstance(v, basestring):
        v = v.strip().replace(',', '.')
        if v.lower() == 'nan':
            return None
        try:
            return float(v)
        except Exception:
            return None
    if isinstance(v, (int, float)):
        return float(v)
    return None

rows = bag.get('scada_sql_rows') or []
total_processed = 0
total_upserts = 0
total_errors = 0

logger.info("[SCADA SQL] Processing %d rows" % len(rows))

for r in rows:
    total_processed += 1
    sensor_id = r.get('sensor_id')
    device_id = r.get('device_id')
    timestamp = r.get('timestamp')
    value = parse_value(r.get('value'))

    if not sensor_id or not device_id or not timestamp or value is None:
        logger.warning("[SCADA SQL] Skipping row: missing required fields")
        total_errors += 1
        continue

    try:
        try:
            date_time_read = datetime.strptime(timestamp, '%Y-%m-%d %H:%M:%S')
            date_time_read = pytz.timezone('Europe/Madrid').localize(date_time_read)
            date_time_read = date_time_read.astimezone(pytz.timezone('UTC'))
            ts_utc = date_time_read.strftime('%Y-%m-%d %H:%M:%S')
        except Exception:
            ts_utc = timestamp

        Remote.upsert(
            'mdm.measurement.device.sensor.reading',
            {
                'sensor_id': sensor_id,
                'measurement_time': ts_utc,
            },
            {
                'value': value,
                'device_id': device_id,
            }
        )
        logger.debug("[SCADA SQL] Upserted reading for sensor %d, timestamp %s" % (sensor_id, ts_utc))
        total_upserts += 1
    except Exception as ex:
        error_msg = str(ex)
        logger.error("[SCADA SQL] Error upserting reading for sensor %d: %s" % (sensor_id, error_msg))
        total_errors += 1

logger.info("[SCADA SQL] Upsert completed: %d processed, %d upserts, %d errors" % (total_processed, total_upserts, total_errors))

bag['upserts'] = total_upserts
bag['errors'] = total_errors
Remote.message_post(
    body='[SCADA SQL] Upsert: %s processed, %s upserts, %s errors' %
         (total_processed, total_upserts, total_errors)
)
